import SharedKit

public enum AppDesignSystem {
    public static let namespace = "{{ project_name }}"
}

import APIClient

public struct AppAPIClientFactory {
    public static func make(baseURL: URL) -> APIClient {
        APIClient(baseURL: baseURL)
    }
}

public enum AppRoute: Hashable {
    case home
    case detail(id: String)
}

public protocol AppStore {
    associatedtype Value
    func load() throws -> Value?
    func save(_ value: Value) throws
}
